/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportwwDuplicataPagar-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&CreCliCod.IsEmpty()) &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = &CreCliCod EndIf
If not (&CreCliRaz.IsEmpty()) &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = WWP_Export_SecureText(&CreCliRaz) EndIf
If not (&CreAbvDup.IsEmpty()) &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = WWP_Export_SecureText(&CreAbvDup) EndIf
If not (&CreDupIsAce.IsEmpty()) &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = WWP_Export_SecureText(&CreDupIsAce) EndIf
If not (&CreFilPgt.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "F.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CreFilPgt EndIf
If not (&CreRecPag.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Receber/Pagar") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &CreRecPag.EnumerationDescription() EndIf
If not (&CreSts.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Status") If Not &CreSts.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &CreSts.EnumerationDescription() Endif EndIf
If not (&CreVlrSdo.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Saldo") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CreVlrSdo EndIf
If not (&CreDtaVct.IsEmpty() AND &CreDtaVct_To.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Vct.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &CreDtaVct WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "à") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &CreDtaVct_To EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'CREDUPNRO' &CreDupNro1.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dup.Nro" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreDupNro1) EndIf Case &DynamicFiltersSelector1 = !'CRECBRNOM' &CreCbrNom1.FromString(&GridStateDynamicFilter.Value) If not &CreCbrNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cob.Nome" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreCbrNom1) EndIf Case &DynamicFiltersSelector1 = !'CREVLRDUP' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CreVlrDup1.FromString(&GridStateDynamicFilter.Value) If not &CreVlrDup1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator1 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "R$ Duplicata", "<") Case &DynamicFiltersOperator1 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "R$ Duplicata", "=") Case &DynamicFiltersOperator1 = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "R$ Duplicata", ">") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CreVlrDup1 EndIf Case &DynamicFiltersSelector1 = !'CREPEDNUM' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CrePedNum1.FromString(&GridStateDynamicFilter.Value) If not &CrePedNum1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator1 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Pedido For.", "<") Case &DynamicFiltersOperator1 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Pedido For.", "=") Case &DynamicFiltersOperator1 = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Pedido For.", ">") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CrePedNum1 EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'CREDUPNRO' &CreDupNro2.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dup.Nro" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreDupNro2) EndIf Case &DynamicFiltersSelector2 = !'CRECBRNOM' &CreCbrNom2.FromString(&GridStateDynamicFilter.Value) If not &CreCbrNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cob.Nome" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreCbrNom2) EndIf Case &DynamicFiltersSelector2 = !'CREVLRDUP' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CreVlrDup2.FromString(&GridStateDynamicFilter.Value) If not &CreVlrDup2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator2 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "R$ Duplicata", "<") Case &DynamicFiltersOperator2 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "R$ Duplicata", "=") Case &DynamicFiltersOperator2 = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "R$ Duplicata", ">") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CreVlrDup2 EndIf Case &DynamicFiltersSelector2 = !'CREPEDNUM' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CrePedNum2.FromString(&GridStateDynamicFilter.Value) If not &CrePedNum2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator2 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Pedido For.", "<") Case &DynamicFiltersOperator2 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Pedido For.", "=") Case &DynamicFiltersOperator2 = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Pedido For.", ">") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CrePedNum2 EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'CREDUPNRO' &CreDupNro3.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dup.Nro" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreDupNro3) EndIf Case &DynamicFiltersSelector3 = !'CRECBRNOM' &CreCbrNom3.FromString(&GridStateDynamicFilter.Value) If not &CreCbrNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cob.Nome" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreCbrNom3) EndIf Case &DynamicFiltersSelector3 = !'CREVLRDUP' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CreVlrDup3.FromString(&GridStateDynamicFilter.Value) If not &CreVlrDup3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator3 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "R$ Duplicata", "<") Case &DynamicFiltersOperator3 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "R$ Duplicata", "=") Case &DynamicFiltersOperator3 = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "R$ Duplicata", ">") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CreVlrDup3 EndIf Case &DynamicFiltersSelector3 = !'CREPEDNUM' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CrePedNum3.FromString(&GridStateDynamicFilter.Value) If not &CrePedNum3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator3 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Pedido For.", "<") Case &DynamicFiltersOperator3 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Pedido For.", "=") Case &DynamicFiltersOperator3 = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Pedido For.", ">") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CrePedNum3 EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&VisibleColumnCount = 0 If &Session.Get(!'wwDuplicataPagarColumnsSelector') <> '' &ColumnsSelectorXML = &Session.Get(!'wwDuplicataPagarColumnsSelector') &ColumnsSelector.FromXml(&ColumnsSelectorXML) Else Do 'InitializeColumnsSelector' EndIf
&ColumnsSelector.Columns.Item(8).IsVisible = False &ColumnsSelector.Columns.Item(9).IsVisible = False &ColumnsSelector.Columns.Item(15).IsVisible = False For &ColumnsSelector_Column in &ColumnsSelector.Columns If &ColumnsSelector_Column.IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = GetMessageText(iif(&ColumnsSelector_Column.DisplayName.IsEmpty(), &ColumnsSelector_Column.ColumnName, &ColumnsSelector_Column.DisplayName)) &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Color = 11 &VisibleColumnCount += 1 EndIf EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FilCod CreRecPag CreDtaVct when &OrderedBy = 1 order EmpCod FilCod CreRecPag (CreDtaVct) when &OrderedBy = 2 order EmpCod CreRecPag CreVlrSdo FilCod CreDupNro when &OrderedBy = 3 order CreDupNro when &OrderedBy = 4 AND &OrderedDsc = False order (CreDupNro) when &OrderedBy = 4 AND &OrderedDsc = True order CreDtaEms when &OrderedBy = 5 AND &OrderedDsc = False order (CreDtaEms) when &OrderedBy = 5 AND &OrderedDsc = True order CreDtaAce when &OrderedBy = 6 AND &OrderedDsc = False order (CreDtaAce) when &OrderedBy = 6 AND &OrderedDsc = True order CreDtaVct when &OrderedBy = 7 AND &OrderedDsc = False order (CreDtaVct) when &OrderedBy = 7 AND &OrderedDsc = True order CrePedNum when &OrderedBy = 8 AND &OrderedDsc = False order (CrePedNum) when &OrderedBy = 8 AND &OrderedDsc = True
using DSwwDuplicataPagar(&CreCliCod, &CreCliRaz, &CreAbvDup, &CreDupIsAce, &CreFilPgt, &CreRecPag , &CreSts, &CreVlrSdo, &CreDtaVct, &CreDtaVct_To, &DynamicFiltersSelector1, &DynamicFiltersOperator1 , &CreDupNro1, &CreCbrNom1, &CreVlrDup1, &CrePedNum1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2 , &DynamicFiltersOperator2, &CreDupNro2, &CreCbrNom2, &CreVlrDup2, &CrePedNum2, &DynamicFiltersEnabled3 , &DynamicFiltersSelector3, &DynamicFiltersOperator3, &CreDupNro3, &CreCbrNom3, &CreVlrDup3, &CrePedNum3)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &VisibleColumnCount = 0 If &ColumnsSelector.Columns.Item(1).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = CrePedLctCod &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(2).IsVisible = True if CreNovCliRaz_Formula.Length() > 30 &CreNovCliRaz = substr(CreNovCliRaz_Formula, 1, 30) + '...' Else &CreNovCliRaz = CreNovCliRaz_Formula EndIf &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = WWP_Export_SecureText(&CreNovCliRaz) &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(3).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = WWP_Export_SecureText(CreDupNro) &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(4).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Date = CreDtaEms &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(5).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Date = CreDtaAce &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(6).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Date = CreDtaVct &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(7).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = CreVlrSdo &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(10).IsVisible = True if CreAbvDup.IsEmpty() or CreAbvDup.IsNull() AtualizaSaldoDuplicata.Call(EmpCod, CreCod, FilCod) &AuxPedido = CreAbvDup_FORMULA Else &AuxPedido = CreAbvDup Endif &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = WWP_Export_SecureText(&AuxPedido) &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(11).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = CreVenCod &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(12).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = CreCbrCod &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(13).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = CreFilPgt &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(14).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = CrePedNum &VisibleColumnCount += 1 EndIf
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'InitializeColumnsSelector'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ColumnsSelector = new WWPColumnsSelector() WWP_ColumnsSelector_Add(&ColumnsSelector, !"CrePedLctCod", '', !'Lct', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&CreNovCliRaz", '', !'Nome/Razão For.', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"CreDupNro", '', !'Número', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"CreDtaEms", '', !'Emis.', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"CreDtaAce", '', !'Aceite', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"CreDtaVct", '', !'Vcto.', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"CreVlrSdo", '', !'À Pagar', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&CreVlrPgt", '', !'Pagou?', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&TipoBaixa", '', !'Baixa', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&AuxPedido", '', !'Origem', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"CreVenCod", '', !'Vnd.', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"CreCbrCod", '', !'LC', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"CreFilPgt", '', !'F.', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"CrePedNum", '', !'Pedido For.', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&Salvar", '', !' ', True, '')
&UserCustomValue = LoadColumnsSelectorState.Udp(!'wwDuplicataPagarColumnsSelector') If not(&UserCustomValue.IsEmpty()) &ColumnsSelectorAux.FromXml(&UserCustomValue) WWP_ColumnSelector_UpdateColumns(&ColumnsSelectorAux, &ColumnsSelector) EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"wwDuplicataPagarGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"wwDuplicataPagarGridState")) Else &GridState.FromXml(&Session.Get(!"wwDuplicataPagarGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"CRECLICOD" &CreCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRECLIRAZ" &CreCliRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREABVDUP" &CreAbvDup.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREDUPISACE" &CreDupIsAce.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREFILPGT" &CreFilPgt.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRERECPAG" &CreRecPag.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRESTS" &CreSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREVLRSDO" &CreVlrSdo.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREDTAVCT" &CreDtaVct.FromString(&GridStateFilterValue.Value) &CreDtaVct_To.FromString(&GridStateFilterValue.ValueTo) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

